+package base64x_test
+
+import (
+	"bytes"
+	"testing"
+
+	"github.com/dleblanc/kindling/internal/base64x"
+)
+
+// TestEncodeLengthAndRoundTrip locks in the regression where the final
+// complete three-byte group was dropped for inputs whose length is an
+// exact multiple of three. It is alphabet-independent: it only asserts
+// the standard encoded length and a full Encode/Decode round-trip.
+func TestEncodeLengthAndRoundTrip(t *testing.T) {
+	for _, n := range []int{0, 1, 2, 3, 4, 6, 9} {
+		data := make([]byte, n)
+		for i := range data {
+			data[i] = byte(i*7 + 1)
+		}
+		enc := base64x.Encode(data)
+		wantLen := 4 * ((n + 2) / 3)
+		if len(enc) != wantLen {
+			t.Fatalf("n=%d encoded len=%d want %d (enc=%q)", n, len(enc), wantLen, enc)
+		}
+		dec, err := base64x.Decode(enc)
+		if err != nil {
+			t.Fatalf("n=%d decode error: %v", n, err)
+		}
+		if !bytes.Equal(dec, data) {
+			t.Fatalf("n=%d round-trip mismatch: got %v want %v", n, dec, data)
+		}
+	}
+}
